example_bad:
mod shapes {
    pub struct Circle {
        radius: f64, // private field
    }
    impl Circle {
        pub fn new(r: f64) -> Circle {
            Circle { radius: r }
        }
    }
}

fn main() {
    let c = shapes::Circle::new(5.0);
    println!("{}", c.radius); // Error: field `radius` is private
}

fixes.code:
pub struct Circle {
    pub radius: f64, // Now accessible outside the module
}

impl Circle {
    pub fn radius(&self) -> f64 {
        self.radius
    }
}

// Usage:
println!("{}", c.radius());
